"use client"

import { useState, useEffect } from "react"
import { useDataStore, type Team } from "@/store/data-store"
import { useAuthStore } from "@/store/auth-store"
import { PageHeader } from "@/components/shared/page-header"
import { EntityStatusBadge } from "@/components/shared/status-badge"
import { Card, CardContent } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
} from "@/components/ui/dialog"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu"
import {
  MoreHorizontal,
  Pencil,
  Eye,
  Search,
  Users,
  Phone,
  Mail,
  GitBranch,
  Crown,
} from "lucide-react"
import { toast } from "sonner"

export default function TeamLeadersPage() {
  const { currentUser } = useAuthStore()
  const { teams, engineers, fetchTeams, fetchEngineers } = useDataStore()
  const [search, setSearch] = useState("")
  const [dialogOpen, setDialogOpen] = useState(false)
  const [detailOpen, setDetailOpen] = useState(false)
  const [editingTeam, setEditingTeam] = useState<Team | null>(null)
  const [viewingTeam, setViewingTeam] = useState<Team | null>(null)
  const [formLeaderId, setFormLeaderId] = useState("")

  // Fetch data on mount
  useEffect(() => {
    fetchTeams()
    fetchEngineers()
  }, [fetchTeams, fetchEngineers])

  // Only DMA managers can access this page
  const isDMAManager = currentUser?.role === "dma_manager"

  if (!isDMAManager) {
    return (
      <div className="flex flex-col gap-6">
        <PageHeader
          title="Team Leaders"
          description="Only DMA Managers can manage Team Leaders"
        />
        <Card>
          <CardContent className="py-12 text-center text-muted-foreground">
            You do not have permission to access this page. Only DMA Managers can manage Team
            Leaders.
          </CardContent>
        </Card>
      </div>
    )
  }

  const filteredTeams = teams.filter((t) => {
    const matchSearch =
      t.name.toLowerCase().includes(search.toLowerCase()) ||
      (t.leaderName?.toLowerCase() || "").includes(search.toLowerCase())
    return matchSearch
  })

  function openEditDialog(team: Team) {
    setEditingTeam(team)
    setFormLeaderId(team.leaderId || "")
    setDialogOpen(true)
  }

  function handleSubmit() {
    if (!formLeaderId) {
      toast.error("Please select a team leader")
      return
    }

    // In a real app, this would call an API to update the team leader
    toast.success("Team leader updated successfully")
    setDialogOpen(false)
  }

  const currentLeader = editingTeam 
    ? engineers.find((e) => e.id === formLeaderId)
    : null

  const viewingLeader = viewingTeam 
    ? engineers.find((e) => e.id === viewingTeam.leaderId)
    : null

  return (
    <div className="flex flex-col gap-6">
      <PageHeader
        title="Team Leaders"
        description="View and manage team leaders assigned to each team"
      />

      {/* Search */}
      <div className="relative max-w-sm">
        <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
        <Input
          placeholder="Search teams..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          className="pl-9"
        />
      </div>

      {/* Table */}
      <Card>
        <CardContent className="p-0">
          <div className="overflow-x-auto">
            <table className="w-full text-sm">
              <thead>
                <tr className="border-b text-left text-muted-foreground">
                  <th className="px-6 py-3 font-medium">Team Name</th>
                  <th className="px-6 py-3 font-medium">Branch</th>
                  <th className="px-6 py-3 font-medium">Current Leader</th>
                  <th className="px-6 py-3 font-medium">Team Members</th>
                  <th className="px-6 py-3 font-medium">Status</th>
                  <th className="px-6 py-3 font-medium text-right">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y">
                {filteredTeams.length === 0 ? (
                  <tr>
                    <td colSpan={6} className="px-6 py-12 text-center text-muted-foreground">
                      No teams found
                    </td>
                  </tr>
                ) : (
                  filteredTeams.map((team) => (
                    <tr key={team.id} className="hover:bg-muted/50">
                      <td className="px-6 py-4 font-medium">
                        <div className="flex items-center gap-2">
                          <Users className="h-4 w-4 text-muted-foreground" />
                          {team.name}
                        </div>
                      </td>
                      <td className="px-6 py-4 text-muted-foreground">
                        <div className="flex items-center gap-2">
                          <GitBranch className="h-3.5 w-3.5" />
                          {team.branchName}
                        </div>
                      </td>
                      <td className="px-6 py-4">
                        <div className="flex items-center gap-2">
                          <Crown className="h-3.5 w-3.5 text-yellow-600" />
                          {team.leaderName || "Unassigned"}
                        </div>
                      </td>
                      <td className="px-6 py-4 text-muted-foreground">{team.memberCount} members</td>
                      <td className="px-6 py-4">
                        <EntityStatusBadge status={team.status} />
                      </td>
                      <td className="px-6 py-4 text-right">
                        <DropdownMenu>
                          <DropdownMenuTrigger asChild>
                            <Button variant="ghost" size="icon" className="h-8 w-8">
                              <MoreHorizontal className="h-4 w-4" />
                              <span className="sr-only">Actions</span>
                            </Button>
                          </DropdownMenuTrigger>
                          <DropdownMenuContent align="end">
                            <DropdownMenuItem onClick={() => {
                              setViewingTeam(team)
                              setDetailOpen(true)
                            }}>
                              <Eye className="mr-2 h-4 w-4" />
                              View Details
                            </DropdownMenuItem>
                            <DropdownMenuItem onClick={() => openEditDialog(team)}>
                              <Pencil className="mr-2 h-4 w-4" />
                              Change Leader
                            </DropdownMenuItem>
                          </DropdownMenuContent>
                        </DropdownMenu>
                      </td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>
        </CardContent>
      </Card>

      {/* Edit Team Leader Dialog */}
      <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Assign Team Leader</DialogTitle>
          </DialogHeader>
          {editingTeam && (
            <div className="flex flex-col gap-4 py-4">
              <div>
                <p className="text-sm font-medium">Team: {editingTeam.name}</p>
                <p className="text-xs text-muted-foreground mt-1">Branch: {editingTeam.branchName}</p>
              </div>
              <div className="flex flex-col gap-2">
                <Label>Select Team Leader</Label>
                <Select value={formLeaderId} onValueChange={setFormLeaderId}>
                  <SelectTrigger>
                    <SelectValue placeholder="Select an engineer as team leader" />
                  </SelectTrigger>
                  <SelectContent>
                    {engineers
                      .filter(
                        (e) =>
                          e.branchId === editingTeam.branchId && e.status === "active"
                      )
                      .map((e) => (
                        <SelectItem key={e.id} value={e.id}>
                          {e.name} ({e.branchName})
                        </SelectItem>
                      ))}
                  </SelectContent>
                </Select>
              </div>
              {currentLeader && (
                <div className="mt-2 p-3 bg-muted rounded-lg">
                  <p className="text-xs text-muted-foreground">New Team Leader</p>
                  <p className="font-medium mt-1">{currentLeader.name}</p>
                </div>
              )}
            </div>
          )}
          <DialogFooter>
            <Button variant="outline" onClick={() => setDialogOpen(false)}>
              Cancel
            </Button>
            <Button onClick={handleSubmit}>Save Changes</Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Detail View Dialog */}
      <Dialog open={detailOpen} onOpenChange={setDetailOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Team Details</DialogTitle>
          </DialogHeader>
          {viewingTeam && (
            <div className="flex flex-col gap-4 py-4">
              <div className="flex items-center gap-4">
                <div className="h-12 w-12 rounded-full bg-blue-100 flex items-center justify-center">
                  <Users className="h-6 w-6 text-blue-600" />
                </div>
                <div>
                  <p className="font-semibold">{viewingTeam.name}</p>
                  <p className="text-sm text-muted-foreground">Team</p>
                </div>
              </div>
              <div className="grid grid-cols-2 gap-4 text-sm">
                <div>
                  <p className="text-muted-foreground text-xs">Branch</p>
                  <p className="flex items-center gap-1 mt-1">
                    <GitBranch className="h-3.5 w-3.5" />
                    {viewingTeam.branchName}
                  </p>
                </div>
                <div>
                  <p className="text-muted-foreground text-xs">Team Members</p>
                  <p className="mt-1 font-medium">{viewingTeam.memberCount}</p>
                </div>
                <div className="col-span-2">
                  <p className="text-muted-foreground text-xs">Team Leader</p>
                  <p className="flex items-center gap-1 mt-1">
                    <Crown className="h-3.5 w-3.5 text-yellow-600" />
                    {viewingLeader?.name || viewingTeam.leaderName || "Unassigned"}
                  </p>
                </div>
                <div className="col-span-2">
                  <p className="text-muted-foreground text-xs">Status</p>
                  <div className="mt-1">
                    <EntityStatusBadge status={viewingTeam.status} />
                  </div>
                </div>
              </div>
            </div>
          )}
        </DialogContent>
      </Dialog>
    </div>
  )
}